// ============================================================
// VerboseDebugTree.kt - Enhanced Timber Debug Tree
// ============================================================
class VerboseDebugTree : Timber.DebugTree() {
    
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    
    override fun createStackElementTag(element: StackTraceElement): String {
        return "(${element.fileName}:${element.lineNumber}) ${element.methodName}"
    }
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = dateFormat.format(Date())
        val threadName = Thread.currentThread().name
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }
        
        val enhancedMessage = "[$timestamp][$priorityChar][$threadName] $message"
        super.log(priority, tag, enhancedMessage, t)
    }
}

// ============================================================
// FileLoggingTree.kt - Writes logs to file for later retrieval
// ============================================================
class FileLoggingTree(private val application: Application) : Timber.Tree() {
    
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val fileDateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
    private val logQueue = ConcurrentLinkedQueue<String>()
    private val executor = Executors.newSingleThreadExecutor()
    private val maxFileSize = 10 * 1024 * 1024L // 10 MB
    private val maxLogFiles = 7
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val timestamp = dateFormat.format(Date())
        val priorityChar = when (priority) {
            Log.VERBOSE -> "V"
            Log.DEBUG -> "D"
            Log.INFO -> "I"
            Log.WARN -> "W"
            Log.ERROR -> "E"
            Log.ASSERT -> "A"
            else -> "?"
        }
        
        val threadName = Thread.currentThread().name
        val logLine = StringBuilder()
        logLine.append("$timestamp [$priorityChar/$tag] [$threadName] $message")
        
        if (t != null) {
            val sw = StringWriter()
            t.printStackTrace(PrintWriter(sw))
            logLine.append("\n").append(sw.toString())
        }
        
        logQueue.add(logLine.toString())
        flushToFile()
    }
    
    private fun flushToFile() {
        executor.execute {
            try {
                val logDir = File(application.filesDir, "logs")
                if (!logDir.exists()) logDir.mkdirs()
                
                val today = fileDateFormat.format(Date())
                val logFile = File(logDir, "app_log_$today.txt")
                
                // Rotate if file too large
                if (logFile.exists() && logFile.length() > maxFileSize) {
                    val rotatedFile = File(logDir, "app_log_${today}_${System.currentTimeMillis()}.txt")
                    logFile.renameTo(rotatedFile)
                }
                
                // Clean old log files
                cleanOldLogs(logDir)
                
                FileWriter(logFile, true).use { writer ->
                    while (logQueue.isNotEmpty()) {
                        val entry = logQueue.poll()
                        if (entry != null) {
                            writer.write(entry)
                            writer.write("\n")
                        }
                    }
                    writer.flush()
                }
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Failed to write log to file", e)
            }
        }
    }
    
    private fun cleanOldLogs(logDir: File) {
        val logFiles = logDir.listFiles()?.sortedByDescending { it.lastModified() } ?: return
        if (logFiles.size > maxLogFiles) {
            logFiles.drop(maxLogFiles).forEach { it.delete() }
        }
    }
    
    fun getLogFiles(): List<File> {
        val logDir = File(application.filesDir, "logs")
        return logDir.listFiles()?.sortedByDescending { it.lastModified() } ?: emptyList()
    }
}

// ============================================================
// CrashReportingTree.kt - Captures errors for crash reporting
// ============================================================
class CrashReportingTree : Timber.Tree() {
    
    private val recentErrors = ConcurrentLinkedQueue<ErrorEntry>()
    private val maxErrors = 100
    
    data class ErrorEntry(
        val timestamp: Long,
        val tag: String?,
        val message: String,
        val throwable: Throwable?,
        val stackTrace: String?
    )
    
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority < Log.WARN) return
        
        val stackTrace = if (t != null) {
            val sw = StringWriter()
            t.printStackTrace(PrintWriter(sw))
            sw.toString()
        } else null
        
        val entry = ErrorEntry(
            timestamp = System.currentTimeMillis(),
            tag = tag,
            message = message,
            throwable = t,
            stackTrace = stackTrace
        )
        
        recentErrors.add(entry)
        while (recentErrors.size > maxErrors) {
            recentErrors.poll()
        }
    }
    
    fun getRecentErrors(): List<ErrorEntry> = recentErrors.toList()
    
    fun clearErrors() = recentErrors.clear()
}

