// ============================================================
// DatabaseLogger.kt - Database query logging
// ============================================================
object DatabaseLogger {
    
    private const val TAG = "DATABASE"
    
    fun logQuery(
        query: String,
        parameters: Map<String, Any?> = emptyMap(),
        tableName: String? = null,
        operationType: String = "SELECT"
    ) {
        val paramsStr = if (parameters.isNotEmpty()) {
            parameters.entries.joinToString("\n|  ") { entry ->
                "${entry.key}: ${sanitizeParam(entry.value)} (${entry.value?.javaClass?.simpleName ?: "null"})"
            }
        } else "none"
        
        Timber.tag(TAG).v(
            """
            |=== DB QUERY ===
            |Operation: $operationType
            |Table: ${tableName ?: "unknown"}
            |Query: $query
            |Parameters:
            |  $paramsStr
            |Timestamp: ${Date()}
            |Thread: ${Thread.currentThread().name}
            |================
            """.trimMargin()
        )
    }
    
    fun logQueryResult(
        query: String,
        rowCount: Int,
        executionTimeMs: Long,
        success: Boolean = true
    ) {
        val logLevel = when {
            executionTimeMs > 5000 -> Log.ERROR
            executionTimeMs > 1000 -> Log.WARN
            executionTimeMs > 500 -> Log.DEBUG
            else -> Log.VERBOSE
        }
        
        val message = """
            |=== DB QUERY RESULT ===
            |Query: $query
            |Rows Returned: $rowCount
            |Execution Time: ${executionTimeMs}ms
            |Success: $success
            |Slow Query: ${executionTimeMs > 500}
            |Timestamp: ${Date()}
            |=======================
        """.trimMargin()
        
        when (logLevel) {
            Log.ERROR -> Timber.tag(TAG).e(message)
            Log.WARN -> Timber.tag(TAG).w(message)
            Log.DEBUG -> Timber.tag(TAG).d(message)
            else -> Timber.tag(TAG).v(message)
        }
    }
    
    fun logTransaction(transactionId: String, operation: String, status: String) {
        Timber.tag(TAG).v(
            """
            |=== DB TRANSACTION ===
            |Transaction ID: $transactionId
            |Operation: $operation
            |Status: $status
            |Timestamp: ${Date()}
            |======================
            """.trimMargin()
        )
    }
    
    fun logInsert(tableName: String, values: Map<String, Any?>, rowId: Long?) {
        val valuesStr = values.entries.joinToString("\n|  ") { 
            "${it.key}: ${sanitizeParam(it.value)}" 
        }
        Timber.tag(TAG).v(
            """
            |=== DB INSERT ===
            |Table: $tableName
            |Values:
            |  $valuesStr
            |Inserted Row ID: ${rowId ?: "failed"}
            |Timestamp: ${Date()}
            |=================
            """.trimMargin()
        )
    }
    
    fun logUpdate(tableName: String, values: Map<String, Any?>, whereClause: String?, rowsAffected: Int) {
        val valuesStr = values.entries.joinToString("\n|  ") { 
            "${it.key}: ${sanitizeParam(it.value)}" 
        }
        Timber.tag(TAG).v(
            """
            |=== DB UPDATE ===
            |Table: $tableName
            |Values:
            |  $valuesStr
            |Where: ${whereClause ?: "none"}
            |Rows Affected: $rowsAffected
            |Timestamp: ${Date()}
            |=================
            """.trimMargin()
        )
    }
    
    fun logDelete(tableName: String, whereClause: String?, rowsAffected: Int) {
        Timber.tag(TAG).v(
            """
            |=== DB DELETE ===
            |Table: $tableName
            |Where: ${whereClause ?: "none"}
            |Rows Affected: $rowsAffected
            |Timestamp: ${Date()}
            |=================
            """.trimMargin()
        )
    }
    
    fun logMigration(fromVersion: Int, toVersion: Int, success: Boolean, durationMs: Long) {
        Timber.tag(TAG).i(
            """
            |=== DB MIGRATION ===
            |From Version: $fromVersion
            |To Version: $toVersion
            |Success: $success
            |Duration: ${durationMs}ms
            |Timestamp: ${Date()}
            |====================
            """.trimMargin()
        )
    }
    
    fun logDatabaseError(operation: String, query: String?, exception: Throwable) {
        Timber.tag(TAG).e(
            exception,
            """
            |=== DB ERROR ===
            |Operation: $operation
            |Query: ${query ?: "N/A"}
            |Error: ${exception.message}
            |Timestamp: ${Date()}
            |================
            """.trimMargin()
        )
    }
    
    private fun sanitizeParam(value: Any?): String {
        return when (value) {
            null -> "NULL"
            is String -> if (value.length > 200) "${value.take(200)}... [truncated, total=${value.length}]" else "\"$value\""
            is ByteArray -> "[ByteArray, size=${value.size}]"
            else -> value.toString()
        }
    }
}

// ============================================================
// ApiLogger.kt - API request/response logging
// ============================================================
object ApiLogger {
    
    private const val TAG = "API"
    private val sensitiveHeaders = setOf(
        "authorization", "cookie", "set-cookie", "x-api-key", "x-auth-token"
    )
    
    fun logRequest(
        method: String,
        url: String,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        queryParams: Map<String, String> = emptyMap(),
        contentType: String? = null,
        requestId: String? = null
    ) {
        val headersStr = if (headers.isNotEmpty()) {
            headers.entries.joinToString("\n|  ") { entry ->
                val value = if (sensitiveHeaders.contains(entry.key.lowercase())) {
                    maskSensitiveValue(entry.value)
                } else {
                    entry.value
                }
                "${entry.key}: $value"
            }
        } else "none"
        
        val queryStr = if (queryParams.isNotEmpty()) {
            queryParams.entries.joinToString("\n|  ") { "${it.key}: ${it.value}" }
        } else "none"
        
        val bodyStr = body?.let { truncateBody(it) } ?: "empty"
        
        Timber.tag(TAG).v(
            """
            |=== API REQUEST ===
            |Request ID: ${requestId ?: UUID.randomUUID().toString().take(8)}
            |Method: $method
            |URL: $url
            |Content-Type: ${contentType ?: "not set"}
            |Headers:
            |  $headersStr
            |Query Parameters:
            |  $queryStr
            |Body:
            |  $bodyStr
            |Timestamp: ${Date()}
            |Thread: ${Thread.currentThread().name}
            |===================
            """.trimMargin()
        )
    }
    
    fun logResponse(
        method: String,
        url: String,
        statusCode: Int,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        durationMs: Long,
        requestId: String? = null,
        contentLength: Long? = null
    ) {
        val headersStr = if (headers.isNotEmpty()) {
            headers.entries.joinToString("\n|  ") { entry ->
                val value = if (sensitiveHeaders.contains(entry.key.lowercase())) {
                    maskSensitiveValue(entry.value)
                } else {
                    entry.value
                }
                "${entry.key}: $value"
            }
        } else "none"
        
        val bodyStr = body?.let { truncateBody(it) } ?: "empty"
        
        val logLevel = when {
            statusCode in 200..299 -> Log.VERBOSE
            statusCode in 300..399 -> Log.DEBUG
            statusCode in 400..499 -> Log.WARN
            statusCode >= 500 -> Log.ERROR
            else -> Log.VERBOSE
        }
        
        val message = """
            |=== API RESPONSE ===
            |Request ID: ${requestId ?: "unknown"}
            |Method: $method
            |URL: $url
            |Status Code: $statusCode
            |Duration: ${durationMs}ms
            |Content Length: ${contentLength ?: "unknown"} bytes
            |Response Headers:
            |  $headersStr
            |Response Body:
            |  $bodyStr
            |Timestamp: ${Date()}
            |====================
        """.trimMargin()
        
        when (logLevel) {
            Log.ERROR -> Timber.tag(TAG).e(message)
            Log.WARN -> Timber.tag(TAG).w(message)
            Log.DEBUG -> Timber.tag(TAG).d(message)
            else -> Timber.tag(TAG).v(message)
        }
    }
    
    fun logRequestError(
        method: String,
        url: String,
        exception: Throwable,
        durationMs: Long,
        requestId: String? = null
    ) {
        Timber.tag(TAG).e(
            exception,
            """
            |=== API REQUEST ERROR ===
            |Request ID: ${requestId ?: "unknown"}
            |Method: $method
            |URL: $url
            |Duration: ${durationMs}ms
            |Error Type: ${exception.javaClass.simpleName}
            |Error Message: ${exception.message}
            |Timestamp: ${Date()}
            |=========================
            """.trimMargin()
        )
    }
    
    fun logRetry(
        method: String,
        url: String,
        attemptNumber: Int,
        maxAttempts: Int,
        reason: String,
        delayMs: Long
    ) {
        Timber.tag(TAG).w(
            """
            |=== API RETRY ===
            |Method: $method
            |URL: $url
            |Attempt: $attemptNumber/$maxAttempts
            |Reason: $reason
            |Delay Before Retry: ${delayMs}ms
            |Timestamp: ${Date()}
            |=================
            """.trimMargin()
        )
    }
    
    fun logTimeout(method: String, url: String, timeoutMs: Long) {
        Timber.tag(TAG).e(
            """
            |=== API TIMEOUT ===
            |Method: $method
            |URL: $url
            |Timeout: ${timeoutMs}ms
            |Timestamp: ${Date()}
            |===================
            """.trimMargin()
        )
    }
    
    fun logCacheHit(url: String, cacheAge: Long) {
        Timber.tag(TAG).v(
            """
            |=== API CACHE HIT ===
            |URL: $url
            |Cache Age: ${cacheAge}ms
            |Timestamp: ${Date()}
            |=====================
            """.trimMargin()
        )
    }
    
    private fun maskSensitiveValue(value: String): String {
        return if (value.length > 8) {
            "${value.take(4)}${"*".repeat(value.length - 8)}${value.takeLast(4)}"
        } else {
            "****"
        }
    }
    
    private fun truncateBody(body: String, maxLength: Int = 2000): String {
        return if (body.length > maxLength) {
            "${body.take(maxLength)}\n... [TRUNCATED - Total length: ${body.length} chars]"
        } else {
            body
        }
    }
}

// ============================================================
// ExceptionLogger.kt - Exception and crash logging
// ============================================================
object ExceptionLogger {
    
    private const val TAG = "EXCEPTION"
    
    fun logException(
        exception: Throwable,
        context: String = "",
        severity: Severity = Severity.ERROR,
        additionalData: Map<String, Any?> = emptyMap()
    ) {
        val sw = StringWriter()
        exception.printStackTrace(PrintWriter(sw))
        val fullStackTrace = sw.toString()
        
        val dataStr = if (additionalData.isNotEmpty()) {
            additionalData.entries.joinToString("\n|  ") { "${it.key}: ${it.value}" }
        } else "none"
        
        val causeChain = buildCauseChain(exception)
        
        val message = """
            |=== EXCEPTION [${severity.name}] ===
            |Context: ${context.ifEmpty { "unspecified" }}
            |Exception Type: ${exception.javaClass.canonicalName}
            |Message: ${exception.message}
            |Cause Chain:
            |  $causeChain
            |Additional Data:
            |  $dataStr
            |Thread: ${Thread.currentThread().name}
            |Timestamp: ${Date()}
            |Full Stack Trace:
            |$fullStackTrace
            |===================================
        """.trimMargin()
        
        when (severity) {
            Severity.CRITICAL -> Timber.tag(TAG).wtf(exception, message)
            Severity.ERROR -> Timber.tag(TAG).e(exception, message)
            Severity.WARNING -> Timber.tag(TAG).w(exception, message)
            Severity.INFO -> Timber.tag(TAG).i(exception, message)
        }
    }
    
    fun logUncaughtException(thread: Thread, exception: Throwable) {
        val sw = StringWriter()
        exception.printStackTrace(PrintWriter(sw))
        
        Timber.tag(TAG).wtf(
            exception,
            """
            |=== UNCAUGHT EXCEPTION ===
            |Thread: ${thread.name} (ID: ${thread.id})
            |Exception Type: ${exception.javaClass.canonicalName}
            |Message: ${exception.message}
            |Cause Chain: ${buildCauseChain(exception)}
            |Timestamp: ${Date()}
            |Full Stack Trace:
            |${sw}
            |==========================
            """.trimMargin()
        )
    }
    
    fun logAnrDetected(stackTraces: Map<Thread, Array<StackTraceElement>>) {
        val tracesStr = stackTraces.entries.joinToString("\n") { (thread, traces) ->
            val traceStr = traces.joinToString("\n    at ") { it.toString() }
            "Thread: ${thread.name} (${thread.state})\n    at $traceStr"
        }
        
        Timber.tag(TAG).e(
            """
            |=== ANR DETECTED ===
            |Timestamp: ${Date()}
            |Thread Dump:
            |$tracesStr
            |====================
            """.trimMargin()
        )
    }
    
    fun logOOM(exception: OutOfMemoryError, memoryInfo: MemoryInfo? = null) {
        Timber.tag(TAG).wtf(
            exception,
            """
            |=== OUT OF MEMORY ===
            |Message: ${exception.message}
            |Available Memory: ${memoryInfo?.availableMemoryMB ?: "unknown"} MB
            |Total Memory: ${memoryInfo?.totalMemoryMB ?: "unknown"} MB
            |Max Memory: ${memoryInfo?.maxMemoryMB ?: "unknown"} MB
            |Timestamp: ${Date()}
            |=====================
            """.trimMargin()
        )
    }
    
    private fun buildCauseChain(throwable: Throwable): String {
        val causes = mutableListOf<String>()
        var current: Throwable? = throwable
        var depth = 0
        
        while (current != null && depth < 10) {
            causes.add("${current.javaClass.simpleName}: ${current.message}")
            current = current.cause
            depth++
        }
        
        return causes.joinToString(" -> ")
    }
    
    enum class Severity {
        INFO, WARNING, ERROR, CRITICAL
    }
    
    data class MemoryInfo(
        val availableMemoryMB: Long,
        val totalMemoryMB: Long,
        val maxMemoryMB: Long
    )
}

// ============================================================
// PerformanceLogger.kt - Performance monitoring
// ============================================================
object PerformanceLogger {
    
    private const val TAG = "PERFORMANCE"
    private val activeTimers = mutableMapOf<String, Long>()
    
    fun startTimer(label: String): String {
        val timerId = "${label}_${System.nanoTime()}"
        activeTimers[timerId] = System.nanoTime()
        Timber.tag(TAG).v("Timer started: $label (ID: $timerId)")
        return timerId
    }
    
    fun stopTimer(timerId: String): Long {
        val startTime = activeTimers.remove(timerId)
        if (startTime == null) {
            Timber.tag(TAG).w("Timer not found: $timerId")
            return -1
        }
        
        val durationMs = (System.nanoTime() - startTime) / 1_000_000
        Timber.tag(TAG).v(
            """
            |=== TIMER RESULT ===
            |Timer ID: $timerId
            |Duration: ${durationMs}ms
            |Timestamp: ${Date()}
            |====================
            """.trimMargin()
        )
        return durationMs
    }
    
    fun logScreenLoad(screenName: String, loadTimeMs: Long) {
        val level = when {
            loadTimeMs > 3000 -> Log.ERROR
            loadTimeMs > 1000 -> Log.WARN
            else -> Log.VERBOSE
        }
        
        val message = """
            |=== SCREEN LOAD ===
            |Screen: $screenName
            |Load Time: ${loadTimeMs}ms
            |Slow: ${loadTimeMs > 1000}
            |Timestamp: ${Date()}
            |===================
        """.trimMargin()
        
        when (level) {
            Log.ERROR -> Timber.tag(TAG).e(message)
            Log.WARN -> Timber.tag(TAG).w(message)
            else -> Timber.tag(TAG).v(message)
        }
    }
    
    fun logMemoryUsage() {
        val runtime = Runtime.getRuntime()
        val usedMemory = (runtime.totalMemory() - runtime.freeMemory()) / (1024 * 1024)
        val freeMemory = runtime.freeMemory() / (1024 * 1024)
        val totalMemory = runtime.totalMemory() / (1024 * 1024)
        val maxMemory = runtime.maxMemory() / (1024 * 1024)
        
        Timber.tag(TAG).v(
            """
            |=== MEMORY USAGE ===
            |Used: ${usedMemory}MB
            |Free: ${freeMemory}MB
            |Total: ${totalMemory}MB
            |Max: ${maxMemory}MB
            |Usage: ${usedMemory * 100 / maxMemory}%
            |Timestamp: ${Date()}
            |====================
            """.trimMargin()
        )
    }
}

