// ============================================================
// LogExporter.kt - Utility to export logs for debugging
// ============================================================
object LogExporter {
    
    fun exportLogs(application: Application): File? {
        try {
            val logDir = File(application.filesDir, "logs")
            if (!logDir.exists()) return null
            
            val exportFile = File(application.cacheDir, "exported_logs_${System.currentTimeMillis()}.txt")
            
            FileWriter(exportFile).use { writer ->
                writer.write("=== APP LOG EXPORT ===\n")
                writer.write("Export Time: ${Date()}\n")
                writer.write("Device: ${android.os.Build.MANUFACTURER} ${android.os.Build.MODEL}\n")
                writer.write("Android: ${android.os.Build.VERSION.RELEASE} (API ${android.os.Build.VERSION.SDK_INT})\n")
                writer.write("========================\n\n")
                
                logDir.listFiles()?.sortedBy { it.lastModified() }?.forEach { logFile ->
                    writer.write("--- ${logFile.name} ---\n")
                    writer.write(logFile.readText())
                    writer.write("\n\n")
                }
            }
            
            Timber.i("Logs exported to: ${exportFile.absolutePath}")
            return exportFile
        } catch (e: Exception) {
            Timber.e(e, "Failed to export logs")
            return null
        }
    }
    
    fun getLogSummary(application: Application): String {
        val logDir = File(application.filesDir, "logs")
        if (!logDir.exists()) return "No logs found"
        
        val files = logDir.listFiles() ?: return "No log files"
        val totalSize = files.sumOf { it.length() }
        
        return """
            Log Files: ${files.size}
            Total Size: ${totalSize / 1024} KB
            Oldest: ${files.minByOrNull { it.lastModified() }?.name ?: "N/A"}
            Newest: ${files.maxByOrNull { it.lastModified() }?.name ?: "N/A"}
        """.trimIndent()
    }
}

// ============================================================
// GlobalExceptionHandler.kt - Catches all uncaught exceptions
// ============================================================
class GlobalExceptionHandler(
    private val defaultHandler: Thread.UncaughtExceptionHandler?
) : Thread.UncaughtExceptionHandler {
    
    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        ExceptionLogger.logUncaughtException(thread, throwable)
        PerformanceLogger.logMemoryUsage()
        
        // Forward to default handler (which may terminate the app)
        defaultHandler?.uncaughtException(thread, throwable)
    }
    
    companion object {
        fun install() {
            val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
            Thread.setDefaultUncaughtExceptionHandler(GlobalExceptionHandler(defaultHandler))
            Timber.v("Global exception handler installed")
        }
    }
}

