// ============================================================
// Usage Examples
// ============================================================
object LoggingUsageExamples {
    
    fun demonstrateAuthLogging() {
        // Login attempt
        AuthLogger.logLoginAttempt("john.doe@example.com", "email_password", "192.168.1.1")
        
        // Successful login
        AuthLogger.logLoginSuccess(
            username = "john.doe@example.com",
            userId = "usr_12345",
            method = "email_password",
            tokenExpiry = System.currentTimeMillis() + 3600000,
            metadata = mapOf(
                "device_id" to "dev_abc123",
                "login_provider" to "local",
                "two_factor" to "false"
            )
        )
        
        // Failed login
        AuthLogger.logLoginFailure(
            username = "john.doe@example.com",
            method = "email_password",
            reason = "Invalid password",
            errorCode = 401,
            attemptCount = 3
        )
        
        // Account locked
        AuthLogger.logAccountLocked("john.doe@example.com", 5, 30)
        
        // Token refresh
        AuthLogger.logTokenRefresh("usr_12345", true, System.currentTimeMillis() + 3600000)
        
        // Logout
        AuthLogger.logLogout("usr_12345", "user_initiated")
    }
    
    fun demonstrateDatabaseLogging() {
        // Query logging
        DatabaseLogger.logQuery(
            query = "SELECT * FROM users WHERE email = ? AND active = ?",
            parameters = mapOf("email" to "john@example.com", "active" to true),
            tableName = "users",
            operationType = "SELECT"
        )
        
        // Query result
        DatabaseLogger.logQueryResult(
            query = "SELECT * FROM users WHERE email = ?",
            rowCount = 1,
            executionTimeMs = 45,
            success = true
        )
        
        // Insert
        DatabaseLogger.logInsert(
            tableName = "users",
            values = mapOf("name" to "John", "email" to "john@example.com", "age" to 30),
            rowId = 42L
        )
        
        // Update
        DatabaseLogger.logUpdate(
            tableName = "users",
            values = mapOf("last_login" to "2024-01-15T10:30:00Z"),
            whereClause = "id = 42",
            rowsAffected = 1
        )
        
        // Error
        try {
            throw RuntimeException("UNIQUE constraint failed: users.email")
        } catch (e: Exception) {
            DatabaseLogger.logDatabaseError("INSERT", "INSERT INTO users (email) VALUES (?)", e)
        }
    }
    
    fun demonstrateApiLogging() {
        // API Request
        ApiLogger.logRequest(
            method = "POST",
            url = "https://api.example.com/v2/users/login",
            headers = mapOf(
                "Content-Type" to "application/json",
                "Authorization" to "Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.example",
                "X-Request-ID" to "req-abc-123",
                "User-Agent" to "MyApp/1.0.0 Android/13"
            ),
            body = """{"email": "john@example.com", "password": "***"}""",
            contentType = "application/json",
            requestId = "req-abc-123"
        )
        
        // API Response
        ApiLogger.logResponse(
            method = "POST",
            url = "https://api.example.com/v2/users/login",
            statusCode = 200,
            headers = mapOf(
                "Content-Type" to "application/json",
                "X-RateLimit-Remaining" to "99"
            ),
            body = """{"token": "jwt_token_here", "user": {"id": "usr_123", "name": "John"}}""",
            durationMs = 350,
            requestId = "req-abc-123",
            contentLength = 256
        )
        
        // API Error
        ApiLogger.logRequestError(
            method = "GET",
            url = "https://api.example.com/v2/data",
            exception = java.net.SocketTimeoutException("Connection timed out"),
            durationMs = 30000,
            requestId = "req-def-456"
        )
        
        // Retry
        ApiLogger.logRetry(
            method = "GET",
            url = "https://api.example.com/v2/data",
            attemptNumber = 2,
            maxAttempts = 3,
            reason = "503 Service Unavailable",
            delayMs = 2000
        )
    }
    
    fun demonstrateExceptionLogging() {
        // Regular exception
        try {
            throw IllegalStateException("User session not initialized")
        } catch (e: Exception) {
            ExceptionLogger.logException(
                exception = e,
                context = "UserProfileFragment.loadProfile()",
                severity = ExceptionLogger.Severity.ERROR,
                additionalData = mapOf(
                    "userId" to "usr_12345",
                    "screen" to "profile",
                    "networkAvailable" to true
                )
            )
        }
        
        // Nested exception
        try {
            try {
                throw java.sql.SQLException("Connection refused")
            } catch (e: Exception) {
                throw RuntimeException("Failed to load user data", e)
            }
        } catch (e: Exception) {
            ExceptionLogger.logException(
                exception = e,
                context = "UserRepository.fetchUser()",
                severity = ExceptionLogger.Severity.CRITICAL
            )
        }
    }
    
    fun demonstratePerformanceLogging() {
        // Timer
        val timerId = PerformanceLogger.startTimer("user_data_load")
        // ... do work ...
        PerformanceLogger.stopTimer(timerId)
        
        // Screen load
        PerformanceLogger.logScreenLoad("HomeFragment", 850)
        
        // Memory usage
        PerformanceLogger.logMemoryUsage()
    }
}